 * @version
 * @date 2018年5月24日 下午5:21:08
 * @author jeesk
 * @since 1.0
 *  使用PreparedStatement和Statement完成 保存学生
 建表语句
create table t_student(

 	id bigint primary key auto_increment,
 	name varchar(20) not null,
 	age int(3) not null,

 );

 *  
