			}
			if (method.isAnnotationPresent(MyAfter.class)) {
				// 判断这一个方法上面 是否有MyAfter这一个注解
				myAfterMethod = method;
			}
			if (method.isAnnotationPresent(MyTest.class)) {
				// 判断这一个方法上面 是否有MyTest这一个注解,有就添加到集合中去
				methodList.add(method);
